function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v, w] => edges) {
        adj[u].push([v, w]);
    }

    // Dijkstra's algorithm with state tracking
    // Each state is (node, hasSwitchUsed)
    // hasSwitchUsed is a boolean indicating whether the switch at the node has been used
    // We use a priority queue to process states in order of increasing cost
    const pq: [number, number, number][] = [];
    pq.push([0, 0, 0]); // (currentNode, hasSwitchUsed, totalCost)
    const dist: Map<string, number> = new Map();
    dist.set("0_0", 0);

    while (pq.length > 0) {
        // Extract the state with the smallest cost
        pq.sort((a, b) => a[2] - b[2]);
        const [u, hasSwitchUsed, cost] = pq.shift()!;
        const key = u + "_" + (hasSwitchUsed ? 1 : 0);

        // If we've already found a better path to this state, skip
        if (dist.get(key) !== undefined && dist.get(key) < cost) {
            continue;
        }

        // If we reached the destination node
        if (u === n - 1) {
            return cost;
        }

        // Explore neighbors
        for (const [v, w] of adj[u]) {
            // Regular edge
            const newCost = cost + w;
            const newKey = v + "_" + (hasSwitchUsed ? 1 : 0);
            if (!dist.has(newKey) || dist.get(newKey) > newCost) {
                dist.set(newKey, newCost);
                pq.push([v, hasSwitchUsed, newCost]);
            }

            // Reverse edge (if switch hasn't been used)
            if (!hasSwitchUsed) {
                const newCostReverse = cost + 2 * w;
                const newKeyReverse = v + "_" + 1;
                if (!dist.has(newKeyReverse) || dist.get(newKeyReverse) > newCostReverse) {
                    dist.set(newKeyReverse, newCostReverse);
                    pq.push([v, 1, newCostReverse]);
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

